n, a, b, c = map(int, input().split())

remainder = (4 - n % 4) % 4
if remainder == 0:
    print(0)
elif remainder == 1:
    print(min(a, b * 3, b + c))
else:
    print(min(a * 2, b, c * 3, c + a))
